const svcRecords  = $('Fetch Services').first().json.records        || [];
const probRecords = $('Fetch Problems').first().json.records         || [];
const artRecords  = $('Fetch Articles').first().json.records         || [];
const recRecords  = $('Fetch Recommendations').first().json.records  || [];
const sigRecords  = $('Fetch Signals').first().json.records          || [];
const prmRecords  = $('Fetch Prompts').first().json.records          || [];

function buildMap(records, field) {
  const m = {};
  for (const r of records) { const v = r.fields && r.fields[field]; if (v) m[String(v).trim().toLowerCase()] = r.id; }
  return m;
}
function uniq(arr) { return [...new Set(arr.filter(Boolean))]; }
// Handle Airtable multi-select (array) or CSV text (comma-string)
function toTags(v) {
  if (!v) return [];
  if (Array.isArray(v)) return v.map(t => String(t).trim().toLowerCase());
  return String(v).split(',').map(t => t.trim().toLowerCase());
}

const svcMap  = buildMap(svcRecords,  'name');
const probMap = buildMap(probRecords, 'title');
const artMap  = buildMap(artRecords,  'title');
const recMap  = buildMap(recRecords,  'title');

const TAG_SVC = {
  'openclaw':['OpenClaw','WhatsApp (OpenClaw Channel)'],
  'n8n':['n8n','Alert Ingest Webhook','EA AI Gateway','Trade Trigger Webhook'],
  'postgresql':['PostgreSQL AIDB'], 'mt5':['MT5 Demo Terminal','MT5 Live Terminal','MT5 Copytrade','MT5 REST Server'],
  'trading':['EA AI Gateway','Trade Trigger Webhook','MT5 REST Server'],
  'caddy':['Caddy Reverse Proxy'], 'telegram':['Telegram Bot'], 'whatsapp':['WhatsApp (OpenClaw Channel)'],
  'gemini':['Gemini API (Google)'], 'openrouter':['OpenRouter'], 'infisical':['Infisical (Secrets)'],
  'monitoring':['Alert Ingest Webhook'], 'security':['Infisical (Secrets)'],
  'analytics':['NN Server'], 'backup':['PostgreSQL AIDB'], 'networking':['Caddy Reverse Proxy'],
};
const AGENT_SVC = {
  'workspace-router':['OpenClaw','n8n'],
  'market-analyzer':['EA AI Gateway','NN Server','MT5 Demo Terminal'],
  'risk-checker':['EA AI Gateway','MT5 Demo Terminal','MT5 Live Terminal'],
  'resource-monitor':['OpenClaw','n8n','PostgreSQL AIDB','Caddy Reverse Proxy','MT5 Demo Terminal','MT5 Live Terminal','NN Server'],
  'signal-classifier':['Alert Ingest Webhook','n8n'],
  'ea-gateway':['EA AI Gateway','MT5 Demo Terminal','MT5 Live Terminal','MT5 REST Server'],
  'health-checker':['OpenClaw','n8n','PostgreSQL AIDB','MT5 REST Server','NN Server'],
};
const TAG_PROB_KW = {
  'openclaw':['openclaw'],'n8n':['n8n'],'mt5':['mt5','wine','socat','numpy'],
  'openrouter':['openrouter'],'gemini':['openclaw telegram','google provider'],
};
const REC_PROB_KW = {'openrouter':['openrouter'],'mt5':['mt5','wine','socat','numpy'],'openclaw':['openclaw'],'n8n':['n8n']};

const patches = [];
function addPatch(table, record, newFields) {
  const has = Object.values(newFields).some(v => Array.isArray(v) ? v.length > 0 : Boolean(v));
  if (!has) return;
  patches.push({ table, recordId: record.id, fields: newFields });
}

// Pass 1: Problems → Services
for (const r of probRecords) {
  const raw = (r.fields && r.fields.affected_services) || '';
  const rawSvcs = Array.isArray(raw) ? raw : String(raw).split(',');
  addPatch('Problems', r, { linked_services: uniq(rawSvcs.map(s => svcMap[String(s).trim().toLowerCase()])) });
}
// Pass 2: Articles → Services
for (const r of artRecords) {
  const tags = toTags(r.fields && r.fields.tags);
  addPatch('Articles', r, { linked_services: uniq(tags.flatMap(t=>(TAG_SVC[t]||[]).map(n=>svcMap[n.toLowerCase()]))) });
}
// Pass 3: Articles → Problems
for (const r of artRecords) {
  const cat = ((r.fields && r.fields.category)||'').toLowerCase();
  if (cat==='architecture'||cat==='decision-record') continue;
  const tags = toTags(r.fields && r.fields.tags);
  addPatch('Articles', r, { linked_problems: uniq(tags.flatMap(t=>(TAG_PROB_KW[t]||[]).flatMap(kw=>Object.entries(probMap).filter(([k])=>k.includes(kw)).map(([,id])=>id)))) });
}
// Pass 4: Recommendations → Articles
for (const r of recRecords) {
  const text=(((r.fields&&r.fields.title)||'')+' '+((r.fields&&r.fields.description)||'')).toLowerCase();
  addPatch('Recommendations', r, { linked_articles: uniq(Object.entries(artMap).filter(([k])=>k.split(' ').filter(w=>w.length>4).slice(0,4).some(w=>text.includes(w))).map(([,id])=>id)) });
}
// Pass 5: Recommendations → Problems
for (const r of recRecords) {
  const text=(((r.fields&&r.fields.title)||'')+' '+((r.fields&&r.fields.description)||'')).toLowerCase();
  addPatch('Recommendations', r, { linked_problems: uniq(Object.entries(REC_PROB_KW).filter(([d])=>text.includes(d)).flatMap(([,kws])=>kws.flatMap(kw=>Object.entries(probMap).filter(([k])=>k.includes(kw)).map(([,id])=>id)))) });
}
// Pass 6: Signals
for (const r of sigRecords) {
  const result=((r.fields&&r.fields.resulted_in)||'').toLowerCase();
  const content=(((r.fields&&r.fields.summary)||'')+' '+((r.fields&&r.fields.raw_content)||'')).toLowerCase();
  const kw=(map)=>uniq(Object.entries(map).filter(([k])=>k.length>=5&&content.includes(k)).map(([,id])=>id));
  const p={};
  if(result==='article'){const ids=kw(artMap);if(ids.length)p.linked_article=[ids[0]];}
  else if(result==='problem'){const ids=kw(probMap);if(ids.length)p.linked_problem=[ids[0]];}
  else if(result==='recommendation'){const ids=kw(recMap);if(ids.length)p.linked_recommendation=[ids[0]];}
  addPatch('Signals', r, p);
}
// Pass 7: Prompts → Services
for (const r of prmRecords) {
  const agent=((r.fields&&r.fields.agent)||'').toLowerCase().trim();
  addPatch('Prompts', r, { linked_services: uniq((AGENT_SVC[agent]||[]).map(n=>svcMap[n.toLowerCase()])) });
}

return patches.map(p => ({ json: p }));

const all   = $input.all();
const ok    = all.filter(i => !i.json.error).length;
const errs  = all.length - ok;
const summary = '✅ *VizionAI Library — Links Refreshed*\n\n' +
  '🔗 Patches applied: ' + ok + '\n❌ Errors: ' + errs + '\n' +
  '_7 passes: Problems→Svcs, Articles→Svcs, Articles→Problems, Recs→Arts, Recs→Problems, Signals, Prompts→Svcs_';
return [{ json: { summary, ok, errs } }];
